THOUGHT: The miscompile comes from InstCombine folding an equality comparison of two GEPs with the same base into an equality comparison of their indices, without guarding against address wrap-around on small pointer sizes. A conservative and correct fix is to only perform this fold when both GEPs are inbounds, which guarantees no pointer wrap. I will patch InstCombineCompares.cpp by inserting an inbounds guard at the beginning of that specific fold, then commit and submit the patch.

```bash
python3 - <<'PY' && git add -A >/dev/null 2>&1 && git commit -m "InstCombine: Require inbounds for folding icmp eq of same-base GEPs to index compare to avoid wraparound on small pointer sizes" >/dev/null && submit-patch
import re, sys, pathlib
p = pathlib.Path("llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp")
s = p.read_text()
# Locate the fold that matches icmp eq of two GEPs with same base and compares indices.
# We search for an if-condition that matches two m_GEP(...) and CmpInst::isEquality(Pred), then inject an inbounds guard at block start.
pat = re.compile(
    r'(\bif\s*\(\s*match\(\s*LHS\s*,\s*m_GEP\([^;]*?\)\s*\)\s*&&\s*'
    r'match\(\s*RHS\s*,\s*m_GEP\([^;]*?\)\s*\)\s*&&\s*'
    r'CmpInst::isEquality\(\s*Pred\s*\)\s*&&\s*LHS->getType\(\)\s*==\s*RHS->getType\(\)\s*\)\s*\{)',
    re.S)
m = pat.search(s)
if not m:
    print("Target fold not found; aborting.", file=sys.stderr)
    sys.exit(1)
start = m.end()
guard = """
    // Guard against address-space wrap-around: only fold if both GEPs are inbounds.
    if (auto *GEPL = dyn_cast<GetElementPtrInst>(LHS)) {
      if (auto *GEPR = dyn_cast<GetElementPtrInst>(RHS)) {
        if (!GEPL->isInBounds() || !GEPR->isInBounds())
          return nullptr;
      } else {
        return nullptr;
      }
    } else {
      return nullptr;
    }
"""
s = s[:start] + guard + s[start:]
p.write_text(s)
print("Patched with inbounds guard.")
PY
